{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "导言：为何学习AI简史？",
      "pages": [
        {
          "title": "课程定位与学习目标",
          "bullets": [
            "本讲面向软件工程专业师生，聚焦技术演进脉络与工程启示",
            "理解AI各阶段的核心范式、关键突破与失败教训",
            "建立历史视角：技术发展非线性，受算力、数据、算法、政策四重驱动"
          ],
          "notes": "开场提问：'如果图灵活到今天，他会最惊讶哪项AI进展？' 引出历史纵深感；强调本课不只讲故事，更提炼对系统设计、架构选型、技术预判的工程启示。"
        }
      ]
    },
    {
      "title": "奠基与幻灭：1950s–1970s",
      "pages": [
        {
          "title": "学科诞生：从图灵测试到达特茅斯会议",
          "bullets": [
            "1950年图灵《计算机器与智能》提出‘模仿游戏’（图灵测试）",
            "1956年达特茅斯会议首次定义‘Artificial Intelligence’术语",
            "早期三杰成果：逻辑理论家（LT）、通用问题求解器（GPS）、感知机（Rosenblatt, 1958）"
          ],
          "notes": "强调‘命名即赋权’——达特茅斯会议不仅是命名，更是学科建制化起点；对比LT（自动证明）与GPS（通用搜索），说明早期‘通用智能’雄心。"
        },
        {
          "title": "第一次寒冬：期望落差与系统性反思",
          "bullets": [
            "1973年莱特希尔报告直指AI‘未兑现通用智能承诺’",
            "符号主义局限暴露：无法处理不确定性、常识推理与知识获取瓶颈",
            "硬件制约：1960年代典型计算机内存仅几十KB，无法支撑复杂推理"
          ],
          "notes": "过渡语：‘寒冬不是失败，而是对范式的压力测试’；举例：MYCIN虽成功但需专家手工编码500条规则，凸显知识工程不可持续性。"
        }
      ]
    },
    {
      "title": "知识工程时代：1980s",
      "pages": [
        {
          "title": "专家系统的黄金十年",
          "bullets": [
            "MYCIN（医学诊断）、DENDRAL（分子结构分析）验证领域专用智能可行性",
            "XCON配置系统为DEC公司年省4000万美元，首个大规模商用AI案例",
            "日本第五代计算机计划（1982）引爆全球AI投资热潮"
          ],
          "notes": "突出工程价值：XCON将订单配置时间从数天缩短至分钟级；提醒学生注意——这是软件工程史上首个‘知识即代码’的大规模实践。"
        },
        {
          "title": "繁荣下的裂痕：为何再次降温？",
          "bullets": [
            "知识获取瓶颈：‘知识工程师’成本高，专家难以形式化隐性经验",
            "脆弱性：规则系统无法泛化，微小输入变化导致完全错误输出",
            "第五代计划未达预期，叠加1987年Lisp机市场崩溃，资金迅速撤离"
          ],
          "notes": "类比现代：类似当前大模型的‘幻觉’问题——都是知识表征与推理机制的根本缺陷；引导思考：我们今天是否在重复‘规则→参数’的范式迁移？"
        }
      ]
    },
    {
      "title": "范式转移：1990s–2000s",
      "pages": [
        {
          "title": "从符号主义到统计学习",
          "bullets": [
            "SVM（1995）与随机森林（1997）确立数据驱动方法的优越性",
            "深蓝（1997）并非‘理解’棋局，而是暴力搜索+精心调优的评估函数",
            "互联网兴起带来海量标注数据（如网页、邮件），为ML提供燃料"
          ],
          "notes": "关键转折点：深蓝是‘工程奇迹’而非‘AI突破’——它没有学习能力，靠的是人类棋谱+超级计算；对比AlphaGo的自我博弈学习，凸显范式差异。"
        },
        {
          "title": "基础设施准备期：静默的积累",
          "bullets": [
            "开源运动兴起（Linux, Apache）奠定协作研发基础",
            "GPU尚未用于AI，但图形学发展为并行计算埋下伏笔",
            "学术界转向概率图模型（贝叶斯网络、HMM），强化不确定性建模能力"
          ],
          "notes": "承上启下：‘没有1990年代的统计工具链和开源文化，就没有2012年的AlexNet爆发’；提示学生关注技术栈的代际继承性。"
        }
      ]
    },
    {
      "title": "深度学习革命：2010s",
      "pages": [
        {
          "title": "三大支柱：数据、算力、算法",
          "bullets": [
            "ImageNet（2009）提供1400万张带标签图像，成为训练基准",
            "GPU并行计算使神经网络训练速度提升10–100倍（NVIDIA CUDA生态成熟）",
            "ReLU激活函数（2011）、Dropout正则（2012）、BatchNorm（2015）解决深层网络训练难题"
          ],
          "notes": "用具体数字建立认知锚点：AlexNet使用2个GPU训练6天；强调‘不是新算法突然出现，而是旧思想在新条件下复活’（如CNN早在1980年代已有雏形）。"
        },
        {
          "title": "里程碑事件：从视觉到语言",
          "bullets": [
            "AlexNet（2012）错误率骤降11%，终结传统CV方法统治地位",
            "AlphaGo（2016）融合蒙特卡洛树搜索与深度神经网络，攻克围棋",
            "Transformer（2017）摒弃RNN序列依赖，开启并行化大模型时代"
          ],
          "notes": "对比教学：展示AlexNet vs. SIFT+BoW的传统流程图；指出Transformer本质是‘全局注意力’——为后续所有大模型提供统一架构原语。"
        }
      ]
    },
    {
      "title": "生成式AI时代：2020s至今",
      "pages": [
        {
          "title": "ChatGPT：现象级产品的工程密码",
          "bullets": [
            "RLHF（人类反馈强化学习）解决对齐问题，使模型输出更符合人类偏好",
            "InstructGPT（2022）是ChatGPT的技术前身，验证指令微调有效性",
            "API生态+插件系统降低集成门槛，推动企业级快速落地"
          ],
          "notes": "破除神话：ChatGPT并非‘突然发明’，而是OpenAI三年技术沉淀（GPT-2→GPT-3→InstructGPT→ChatGPT）；强调RLHF是软件工程问题（标注、奖励建模、PPO训练）而非纯AI问题。"
        },
        {
          "title": "中国大模型竞速：技术路径与生态特色",
          "bullets": [
            "文心一言（百度）：强中文语义+搜索知识图谱融合",
            "通义千问（阿里）：开源策略激进（Qwen1.5系列全量开放权重）",
            "ChatGLM/DeepSeek：专注推理优化与长上下文支持（如DeepSeek-V2支持128K）"
          ],
          "notes": "联系课程：对比各模型API设计文档，分析其SDK封装粒度、流式响应机制、Token计费模型——这正是软件工程关注的接口契约与服务治理问题。"
        }
      ]
    },
    {
      "title": "挑战与未来：超越技术奇点",
      "pages": [
        {
          "title": "现实约束：幻觉、能耗与对齐",
          "bullets": [
            "幻觉本质：概率生成缺乏事实核查机制，非‘说谎’而是‘自信编造’",
            "训练GPT-3碳排放≈130吨CO₂（相当于5辆汽车终身排放），绿色AI成刚需",
            "对齐难题：如何让AI目标函数与人类复杂价值观一致？尚无数学解"
          ],
          "notes": "警示案例：医疗问答中幻觉可能致命；引导讨论：‘作为软件工程师，你能在系统层做哪些缓解？（如RAG引入可信源、输出置信度标注、人工审核门控）’"
        },
        {
          "title": "前沿方向：从工具到伙伴",
          "bullets": [
            "AI Agent：自主规划、调用工具、迭代反思（如AutoGen、LangChain架构）",
            "具身智能：机器人本体+多模态大模型，实现物理世界闭环控制",
            "小模型复兴：TinyLlama、Phi-3等在端侧实现实时推理，平衡性能与隐私"
          ],
          "notes": "回归课程本质：Agent系统本质是分布式任务调度框架；强调‘下一代软件工程师的核心能力：设计人-AI协同工作流，而非仅写代码’。"
        }
      ]
    },
    {
      "title": "结语：历史给软件工程师的启示",
      "pages": [
        {
          "title": "可迁移的工程智慧",
          "bullets": [
            "技术选型需判断所处范式周期（萌芽/爆发/整合/成熟），避免过早押注或过晚入场",
            "架构设计应预留‘范式切换’接口（如模型抽象层、提示词管理模块）",
            "AI系统可靠性=算法鲁棒性×工程健壮性×人机协同机制"
          ],
          "notes": "总结升华：‘读史使人明智，读AI史则让人清醒——所有颠覆都藏在旧文献里，所有泡沫都源于忽视工程约束’；推荐延伸阅读：《AI Superpowers》《The Alignment Problem》。"
        }
      ]
    }
  ]
}
